import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrintWithValidAppendable() throws IOException {
        Appendable appendable = mock(Appendable.class);
        CSVPrinter printer = csvFormat.print(appendable);
        assertNotNull(printer);

        // Use reflection to access private field 'out' in CSVPrinter
        Appendable out = null;
        try {
            var field = CSVPrinter.class.getDeclaredField("out");
            field.setAccessible(true);
            out = (Appendable) field.get(printer);
        } catch (ReflectiveOperationException e) {
            fail("Reflection failed: " + e.getMessage());
        }

        assertEquals(appendable, out);
    }

    @Test
    void testPrintWithAppendableThatThrowsIOException() {
        Appendable appendable = mock(Appendable.class);
        try {
            doThrow(new IOException("Test IOException")).when(appendable).append(any(CharSequence.class));
        } catch (IOException e) {
            // won't happen on mock setup
        }
        IOException thrown = assertThrows(IOException.class, () -> {
            // The IOException will not be thrown on print() call,
            // because print() only constructs CSVPrinter and does not call append.
            // So we need to trigger append to throw IOException.
            CSVPrinter printer = csvFormat.print(appendable);
            printer.print("test"); // This will call append and throw IOException
        });
        assertEquals("Test IOException", thrown.getMessage());
    }

}
